SELECT
    a.*,
    a.created_time as createdTime,
    a.audit_datetime as auditDatetime,
    IF(a.lock_name = #{adminName}, -1, 5) reviewOperation1
FROM agent_user_overflow a


        AND a.site_code = #{vo.siteCode}


        AND a.created_time  >=  #{vo.applyTimeStart}


        AND a.created_time  <=  #{vo.applyTimeEnd}


        AND a.audit_datetime  >=  #{vo.auditTimeStart}


        AND a.audit_datetime  <=  #{vo.auditTimeEnd}


        AND a.transfer_agent_name = #{vo.transferAgentName}


        AND a.event_id = #{vo.eventId}


        AND a.audit_step = #{vo.auditStep}


        AND a.audit_status = #{vo.auditStatus}


        AND a.apply_name = #{vo.applyName}


        AND a.audit_name = #{vo.auditName}


        AND a.lock_status = #{vo.lockStatus}


        AND a.member_name = #{vo.memberName}


        AND a.user_register = #{vo.userRegister}


        AND a.agent_type = #{vo.agentType}





        ORDER BY createdTime asc


        ORDER BY createdTime desc



        ORDER BY auditDatetime asc


        ORDER BY auditDatetime desc



        ORDER BY reviewOperation1 ASC, a.audit_step DESC, a.audit_status ASC, a.created_time ASC

select
   member_name
from agent_user_overflow
where 1 = 1
and site_code =#{siteCode}

    AND transfer_agent_name in

        #{value}


and audit_status = 2

    AND audit_datetime  >=  #{startTime}


    AND audit_datetime  <=  #{endTime}
